#include<bits/stdc++.h>
using namespace std;
long long qzh[505][505],n,m,K,x,y,ans=0;
long long a[505][505];
int main(void){
	cin>>n>>m>>K;
    for(int i=1;i<=n;i++)for(int j=1;j<=m;j++)cin>>a[i][j];
	for(int i=1;i<=n;i++)for(int j=1;j<=m;j++)qzh[i][j]=qzh[i-1][j]+qzh[i][j-1]-qzh[i-1][j-1]+a[i][j];
	for(int i=1;i<=n;i++){
		for(int j=i;j<=n;j++){
			for(int r=1,l=1;r<=m;r++){
				while(l<=r&&qzh[j][r]-qzh[i-1][r]-qzh[j][l-1]+qzh[i-1][l-1]>K)l++;
				ans+=r-l+1;
			}
		}
	}cout<<ans;
	return false;
}
